solutions.javascript:
// Solution
function validateHtml(html) {
    // Split the input string into individual attributes
    let attributes = html.split(' ');

    // Iterate over the attributes
    for (let attribute of attributes) {
        // Check if the attribute starts with 'class', 'id', 'style', 'src', 'href', or 'alt'
        if (attribute.startsWith('class') || attribute.startsWith('id') || attribute.startsWith('style') || attribute.startsWith('src') || attribute.startsWith('href') || attribute.startsWith('alt')) {
            // If it does, continue to the next attribute
            continue;
        }

        // If the attribute does not start with an allowed attribute, return false
        return false;
    }

    // If all attributes are valid, return true
    return true;
}
